hitMacro.command:
const tgts = (typeof targets !== "undefined" && targets?.length)
  ? targets
  : Array.from(game.user.targets);
if (!tgts.length) return ui.notifications.warn("No token targeted.");

for (const t of tgts) {
  await t.actor.toggleStatusEffect("charmed", { active: true });
}

//ui.notifications.info(`Control applied to ${tgts.length} target(s).`);
